export type IsomerismPart = { number: number; title: string; source: string; topics: string[]; body: string[]; rule?: string; example?: string };

const baseIsomerismParts: IsomerismPart[] = [
  { number: 1, title: "Introduction and classification", source: "Isomerism pp. 1–2", topics: ["isomers", "constitutional", "stereoisomers"], body: ["Isomers have the same molecular formula but differ in the arrangement of atoms. Constitutional (structural) isomers have different connectivity; stereoisomers have the same connectivity but a different spatial arrangement.", "The source classification divides stereoisomerism into configurational and conformational isomerism; configurational isomerism includes geometrical and optical isomerism."], rule: "Never decide isomerism from a formula alone: first compare connectivity, then compare three-dimensional arrangement." },
  { number: 2, title: "Chain and position isomerism", source: "Isomerism pp. 2–7", topics: ["chain", "position", "parent chain"], body: ["Chain isomers have the same molecular formula but a different carbon skeleton or parent-chain length. Alkanes begin to show chain isomerism from four carbon atoms onward.", "Position isomers have the same molecular formula and parent-chain length but differ in the location of a functional group, multiple bond or substituent. A positional change must not change the carbon skeleton."], example: "C₄H₁₀: butane and 2-methylpropane are chain isomers. 1-propanol and 2-propanol are position isomers." },
  { number: 3, title: "Ring-chain, functional and metamerism", source: "Isomerism pp. 8–22", topics: ["ring-chain", "functional", "metamerism"], body: ["Ring-chain isomerism arises when one isomer is open-chain and another is cyclic. Functional isomers have the same molecular formula but different functional groups, such as alcohol/ether, aldehyde/ketone, acid/ester and nitrile/isonitrile.", "Metamerism is produced by unequal distribution of carbon atoms on either side of a polyvalent functional group such as –O–, –S–, –NH– or >C=O. It is not applicable when a side cannot contain carbon."], example: "C₃H₆: propene and cyclopropane are ring-chain isomers; C₂H₆O: ethanol and dimethyl ether are functional isomers." },
  { number: 4, title: "Tautomerism: concept and mechanism", source: "Isomerism pp. 23–50", topics: ["tautomers", "keto-enol", "acid-base catalysis"], body: ["Tautomerism is a dynamic structural isomerism caused by migration of a proton together with displacement of a π bond. Tautomers are interconvertible and exist in equilibrium; they are functional isomers, not resonance forms.", "Keto–enol tautomerism requires an α-hydrogen adjacent to a carbonyl group. In base catalysis the base removes α-H to form an enolate, which is protonated at oxygen. In acid catalysis the carbonyl oxygen is protonated before α-deprotonation."], rule: "Do not draw keto and enol forms with resonance arrows. Use an equilibrium arrow." },
  { number: 5, title: "Tautomerism: types and stability", source: "Isomerism pp. 51–70", topics: ["enolisation", "ring-chain", "annular", "stability"], body: ["The notes cover keto–enol, nitro–aci-nitro, imine–enamine, amide–imidic acid, ring-chain and annular tautomerism. Acid and base both catalyse tautomerisation; neither is consumed overall.", "The more stable tautomer is favoured by stronger bonding, aromaticity, conjugation, intramolecular hydrogen bonding, lower steric strain and solvent effects. Carbonyl bonding commonly favours keto form, while aromaticity and chelation can strongly favour an enol."], example: "Phenol is not treated as an ordinary keto–enol tautomer pair because loss of aromatic stabilization would be severe." },
  { number: 6, title: "Geometrical isomerism and its conditions", source: "Isomerism pp. 71–88", topics: ["restricted rotation", "alkenes", "rings", "cumulenes"], body: ["Geometrical isomerism needs restricted rotation and two distinguishable substituents at each relevant end. For C=C, each double-bond carbon must carry two different groups. Mere presence of a double bond is insufficient.", "The source applies the same spatial test to cyclic compounds, cycloalkenes, C=N/N=N systems, cumulated polyenes and spiranes. In a ring, substituents may be on the same side (cis) or opposite sides (trans)."], rule: "If either end of the double bond has two identical groups, E/Z geometrical isomerism is impossible." },
  { number: 7, title: "Cis–trans and E/Z nomenclature", source: "Isomerism pp. 89–103", topics: ["cis-trans", "E/Z", "CIP"], body: ["cis/trans is useful when an identical pair of substituents supplies an unambiguous reference. E/Z is the general IUPAC system and is assigned independently at each end using Cahn–Ingold–Prelog priorities.", "Rank direct atoms by atomic number. If tied, compare the next attached atoms in descending order until the first difference. Treat multiple bonds as attachment to duplicate atoms. Higher-priority groups on the same side give Z (zusammen); on opposite sides give E (entgegen)."], example: "For CH₃CH=CHCl, Cl outranks H and CH₃ outranks H; compare the two high-priority groups to assign E or Z." },
  { number: 8, title: "Geometrical-isomer properties and counting", source: "Isomerism pp. 104–121", topics: ["dipole moment", "stability", "counting"], body: ["Geometrical isomers can differ in polarity, boiling point, melting point, solubility and chemical behaviour. A trans isomer often has lower dipole moment where bond moments cancel, but symmetry can make melting-point trends non-simple.", "For independent geometrical elements the upper limit is 2ⁿ. Reduce this count when symmetry makes arrangements identical or when a nominal element does not satisfy the distinguishable-substituent condition."], rule: "Count only valid independent stereogenic double bonds; do not mechanically use 2ⁿ." },
  { number: 9, title: "Conformations and projection formulae", source: "Isomerism pp. 122–135", topics: ["Newman", "sawhorse", "Fischer", "torsion"], body: ["Conformers interconvert by rotation about a σ bond without bond breaking. Newman projection looks directly along the C–C bond: the front carbon is a dot and the rear carbon is a circle. Sawhorse is an oblique bond view.", "In a Fischer projection, horizontal bonds project toward the observer and vertical bonds project away. Rotation of the entire Fischer formula by 180° preserves configuration; a 90° rotation or one interchange reverses configuration."], rule: "A Fischer projection is an eclipsed Newman view; preserve front/rear positions during conversion." },
  { number: 10, title: "Ethane, butane and cyclohexane conformations", source: "Isomerism pp. 136–160", topics: ["staggered", "eclipsed", "anti", "gauche", "chair"], body: ["Ethane has staggered (minimum torsional strain) and eclipsed (maximum torsional strain) conformations. Butane has anti, gauche, eclipsed and fully eclipsed conformations; anti is lowest in energy and the CH₃–CH₃ eclipsed form is highest.", "Cyclohexane chair is the most stable common conformation. Boat has flagpole and eclipsing interactions; twist-boat reduces these. Ring flip exchanges axial and equatorial positions while retaining up/down orientation."], example: "In substituted cyclohexane, a bulky group usually prefers equatorial placement to minimize 1,3-diaxial interactions." },
  { number: 11, title: "Optical activity and polarimetry", source: "Optical Isomerism pp. 1–10", topics: ["PPL", "d/l", "specific rotation"], body: ["Optically active compounds rotate plane-polarised light. Clockwise rotation is dextrorotatory, (+) or d; anticlockwise rotation is levorotatory, (−) or l. These signs are experimental observations, not R/S labels.", "A polarimeter uses a monochromatic light source, polariser, sample tube and analyser. Optical rotation depends on concentration, path length, temperature and wavelength."], rule: "Do not infer (+)/(−) from R/S, D/L or molecular formula." },
  { number: 12, title: "Chirality and elements of symmetry", source: "Optical Isomerism pp. 11–35", topics: ["chirality", "mirror plane", "inversion centre", "Sₙ"], body: ["A chiral object is not superimposable on its mirror image. Chirality is destroyed by an improper symmetry element: a plane of symmetry (σ), centre of inversion (i) or improper axis (Sₙ). Presence of a chiral carbon is sufficient in many cases but is neither necessary nor by itself always conclusive.", "A stereogenic centre is an atom at which interchanging two groups produces a stereoisomer. A tetrahedral carbon bearing four different substituents is the familiar example."], rule: "Test the whole molecule for internal symmetry before declaring it optically active." },
  { number: 13, title: "Enantiomers, diastereomers, meso and racemates", source: "Optical Isomerism pp. 36–58", topics: ["enantiomer", "diastereomer", "meso", "racemic"], body: ["Enantiomers are non-superimposable mirror images and have identical ordinary physical properties in an achiral environment, except equal and opposite optical rotation. Diastereomers are stereoisomers that are not mirror images and commonly have different physical properties.", "A meso compound has stereogenic centres but is achiral because of internal symmetry. A racemic mixture contains equal amounts of enantiomers and is optically inactive by external compensation; resolution separates its enantiomers."], example: "For a molecule with two equivalent stereogenic centres, RR/SS may be an enantiomeric pair while RS can be meso." },
  { number: 14, title: "R/S nomenclature and CIP priorities", source: "Optical Isomerism pp. 59–78", topics: ["R/S", "CIP", "priority"], body: ["Assign priorities 1–4 by CIP rules. Orient group 4 away; trace 1→2→3. Clockwise is R and anticlockwise is S. If group 4 points toward the observer, reverse the observed result.", "For isotopes, higher mass number gets higher priority. Compare tied carbon substituents atom-by-atom outward; use duplicated attachments for multiple bonds. R/S describes configuration and does not prescribe optical-rotation sign."], rule: "Lowest priority on a Fischer horizontal bond points forward, so reverse the clockwise/anticlockwise result." },
  { number: 15, title: "Counting stereoisomers and special cases", source: "Optical Isomerism pp. 79–101", topics: ["2ⁿ", "meso reduction", "pseudoasymmetry"], body: ["For n independent stereogenic elements, 2ⁿ is an upper bound. Identical stereogenic centres, internal symmetry and meso forms reduce the count. Treat E/Z elements and tetrahedral centres together only after checking independence and symmetry.", "A pseudo-asymmetric centre is attached to four different groups where two are enantiomorphic; it is labelled r/s (lower-case) by CIP convention and does not by itself create an enantiomeric pair."], rule: "List configurations or use symmetry pairing before finalising a stereoisomer count." },
  { number: 16, title: "Chirality without chiral carbon and heteroatom chirality", source: "Optical Isomerism pp. 102–119", topics: ["allenes", "biphenyls", "spiro", "atropisomerism"], body: ["The notes include axial chirality in allenes and substituted biphenyls (atropisomerism from restricted rotation), spiro/hemispiro systems and chirality at nitrogen, phosphorus and sulphur. These structures must be judged from their three-dimensional symmetry, not from a search for C*.", "Amines usually invert rapidly and are ordinarily not resolvable, whereas suitably substituted quaternary ammonium, phosphorus and sulphur systems may retain configurational stability."], rule: "Restricted rotation produces isolable atropisomers only when the barrier is high enough on the observational timescale." },
  { number: 17, title: "Visual stereoisomer-counting table", source: "Optical Isomerism pp. 92–93", topics: ["counting", "meso", "geometrical", "optical"], body: ["The source table counts meso and optically active stereoisomers separately for structure-specific cases. Each count requires an actual symmetry inspection rather than a formula-only shortcut."], rule: "Use 2ⁿ only as an upper limit; examine the displayed molecular symmetry before accepting it." },
  { number: 18, title: "Visual stereoisomer-counting table II", source: "Optical Isomerism p. 94", topics: ["counting", "meso", "geometrical", "optical"], body: ["Source-table structures 14–18 combine cyclic, acyclic, and geometrical stereogenic elements. Their counts are preserved separately so that symmetry reduction remains structure-specific."], rule: "Count a meso form only after locating a real internal symmetry element in the displayed configuration." },
  { number: 19, title: "Visual stereoisomer-counting table III", source: "Optical Isomerism p. 94", topics: ["counting", "meso", "geometrical", "optical"], body: ["Source-table structures 19–23 complete the page’s cyclic and acyclic stereoisomer-counting set. Their m/a/total entries are retained as individual exercises."], rule: "A symmetry-equivalent EZ and ZE pair is one configuration, but a structure with non-equivalent stereocentres may retain its full 2ⁿ count." },
  { number: 20, title: "Visual stereoisomer-counting table IV", source: "Optical Isomerism p. 95", topics: ["counting", "meso", "rings", "optical"], body: ["The first page-95 source cases combine ring stereochemistry with non-equivalent carbon centres. Each source result is tied to a separately rendered molecular graph."], rule: "Use molecular symmetry, not apparent shape alone, to decide whether a meso arrangement exists." },
  { number: 21, title: "Visual stereoisomer-counting table V", source: "Optical Isomerism p. 95", topics: ["counting", "meso", "polyenes", "optical"], body: ["The second page-95 source group includes halogenated rings, an acyclic five-centre chain, and a polyene/alcohol system. Each retains its source-specific meso, optical and total count."], rule: "Count alkene geometry and tetrahedral configuration independently only when the structure makes both elements valid." },
  { number: 22, title: "Visual stereoisomer-counting table VI", source: "Optical Isomerism p. 96", topics: ["counting", "meso", "polyenes", "optical"], body: ["The source page closes this table group with a substituted diene, butane-2,3-diol, and a halogenated enyne. The displayed counts are preserved as individual cases."], rule: "A meso form needs a genuine internal symmetry element; a visible pair of similar substituents alone is not enough." },
  { number: 23, title: "Fischer projection conventions", source: "Optical Isomerism p. 97", topics: ["Fischer", "projection", "rotation", "interchange"], body: ["A Fischer formula represents a three-dimensional structure on paper: vertical bonds point away and horizontal bonds point toward the observer. The source shows both a valid 180° whole-projection rotation and an invalid 90° rotation."], rule: "A 180° Fischer rotation preserves configuration; a 90° rotation or one interchange reverses it." },
  { number: 24, title: "Fischer comparison and manipulation", source: "Optical Isomerism p. 98", topics: ["Fischer", "comparison", "permutation", "identity"], body: ["A Fischer formula must remain in the plane of the paper: turning it over is not allowed. The source additionally permits a cyclic rotation of three groups while a fourth remains fixed, which preserves configuration."], rule: "Do not flip a Fischer projection through the plane; only approved in-plane operations preserve its stereochemical meaning." },
  { number: 25, title: "Wedge–dash and Fischer interconversion", source: "Optical Isomerism p. 99", topics: ["wedge", "dash", "Fischer", "conversion"], body: ["Wedge–dash notation encodes depth directly: a solid wedge points toward and a hashed wedge points away. The source shows how to orient a labelled tetrahedral centre so that the appropriate groups become vertical or horizontal in a Fischer formula."], rule: "When converting, retain group identities and spatial relationships; never create the Fischer drawing by a single arbitrary interchange." },
  { number: 26, title: "Halogenated wedge–Fischer conversions", source: "Optical Isomerism p. 100", topics: ["wedge", "Fischer", "halogens", "conversion"], body: ["The source converts one- and two-centre halogenated wedge–dash structures into Fischer forms by retaining the carbon backbone and assigning vertical/horizontal depth correctly."], rule: "Convert every stereocentre independently while keeping the full molecular connectivity unchanged." },
  { number: 27, title: "Fischer–wedge conversion applications", source: "Optical Isomerism p. 101", topics: ["Fischer", "wedge", "conversion", "rings"], body: ["The source applies Fischer/wedge conversion to long chains, halogenated systems, cyclic structures and a glyceric-acid-type stereocentre. Multiple wedge drawings can be different rotated views of the same configuration."], rule: "Distinguish a true rotation of one stereochemical drawing from an enantiomeric inversion." },
  { number: 28, title: "Sawhorse and projection interconversion", source: "Optical Isomerism p. 102", topics: ["Sawhorse", "Newman", "Fischer", "ethane"], body: ["Sawhorse shows the C–C bond obliquely. The source contrasts staggered and eclipsed ethane and relates Fischer to an eclipsed Newman view."], rule: "Keep front and rear carbon group membership fixed when converting projections." },
  { number: 29, title: "Two-centre Fischer–Newman conversion", source: "Optical Isomerism p. 103", topics: ["Fischer", "Newman", "two stereocentres", "rotation"], body: ["The source converts a two-centre Fischer formula to an eclipsed Newman projection and shows that a 180° rotation of the entire Newman drawing gives the same Fischer formula.", "For a perspective formula, identify the carbon backbone first, place it vertically in Fischer form, and assign toward-observer groups horizontally."], rule: "Rotate the whole Newman projection by 180°; do not independently interchange groups at only one stereocentre." },
  { number: 30, title: "Identify optically active compounds", source: "Optical Isomerism p. 105", topics: ["axial chirality", "atropisomerism", "symmetry", "biaryls"], body: ["This source page asks for optically active structures across bridged systems, substituted biaryls, heterobiaryls and a constrained cumulated system. The correct decision needs both configurational stability and absence of improper symmetry."], rule: "Do not call a biaryl optically active from ortho crowding alone: check the symmetry of the locked conformation." },
  { number: 31, title: "Identify optically active constrained rings", source: "Optical Isomerism p. 106", topics: ["ring chirality", "allenes", "cycloalkenes", "symmetry"], body: ["Thirty source structures test chirality in small constrained rings and cumulated/exocyclic double-bond systems. Each must be assessed by its actual locked geometry and symmetry."], rule: "A wedge/dash pattern proves only direction: test the whole molecule for an improper symmetry element before concluding it is active." },
  { number: 32, title: "Constrained-system optical activity", source: "Optical Isomerism p. 107", topics: ["constrained rings", "bridge systems", "symmetry"], body: ["Source items 54–78 test optical activity in rigid cycloalkenes, halogenated rings and bridged frameworks."], rule: "Rigid conformation alone does not ensure chirality: test for improper symmetry." },
  { number: 33, title: "Chirality exercise: fixed rings and spiro systems", source: "Optical Isomerism p. 108", topics: ["chirality", "spiro", "rings", "symmetry"], body: ["This source question bank tests 18 fixed cyclic, spiro and fused structures. The conclusion follows from their complete three-dimensional symmetry, not from a single structural feature."], rule: "Retain all wedge/dash and double-bond constraints before looking for a plane, centre or improper axis." },
  { number: 34, title: "Chirality exercise: heterocycles and constrained systems", source: "Optical Isomerism p. 109", topics: ["chirality", "heterocycles", "symmetry", "constrained systems"], body: ["This source page contains structures 19–37: bridged systems, oxygen heterocycles, aryl-substituted rings, a large aromatic framework and a substituted alkene."], rule: "The presence of oxygen changes ring paths; redraw the full fixed stereochemical structure before judging chirality." },
  { number: 35, title: "Chlorinated alkene configurations", source: "Optical Isomerism p. 110, items 38–42", topics: ["chirality", "alkenes", "wedge-dash", "symmetry"], body: ["The first source subgroup on page 110 contains five configurations of the same chlorinated alkene skeleton. Each has its own visible solid/hashed wedge pattern."], rule: "Keep the entire alkene framework fixed and test all stereogenic elements together; a single local wedge change can alter the symmetry class." },
  { number: 36, title: "Conformational-framework exercise", source: "Optical Isomerism p. 110, items 43–48", topics: ["conformations", "heterocycles", "rings", "chirality"], body: ["This source subgroup includes oxygen heterocycles, linked cyclobutanes and ring conformations. Their perspective bonds are part of the structural information."], rule: "Do not flatten a conformational drawing before testing chirality; preserve every indicated front/back bond." },
  { number: 37, title: "Rigid cages and carbohydrate projections", source: "Optical Isomerism p. 110, items 49–58", topics: ["cages", "carbohydrates", "Fischer", "chirality"], body: ["The final source subgroup combines rigid polycyclic cages with oxygen-rich perspective and Fischer-style carbohydrate structures."], rule: "For a rigid cage inspect its complete symmetry; for a Fischer formula preserve horizontal-forward and vertical-back directions." },
  { number: 38, title: "Framework, cage and helical chirality", source: "Optical Isomerism p. 111, items 59–67", topics: ["helical chirality", "cages", "symmetry", "wedge-dash"], body: ["This source subgroup spans fixed carbon frameworks, rigid polyhedra and a helix. It demonstrates that no one drawing convention decides chirality."], rule: "Treat every three-dimensional framework as a whole; a chiral axis or helix does not require a chiral carbon." },
  { number: 39, title: "Spiro and fused small-ring chirality", source: "Optical Isomerism p. 111, items 68–78", topics: ["spiro chirality", "fused rings", "symmetry", "alkynes"], body: ["This source subgroup compares spiro/fused small-ring systems with varying substituent and bond patterns."], rule: "At a spiro junction, compare both ring paths in each perpendicular ring before assigning a stereogenic axis." },
  { number: 40, title: "Cyclic and cumulated-system exercise", source: "Optical Isomerism p. 112, items 79–89", topics: ["cumulenes", "alkenes", "rings", "chirality"], body: ["This source subgroup includes substituted cyclic alkenes, cumulenes/dienes, cyclohexene and a symmetry comparison symbol."], rule: "Restricted bond geometry matters: do not flatten a cumulated or cyclic structure before testing its symmetry." },
  { number: 41, title: "Projection and atropisomerism exercise", source: "Optical Isomerism p. 112, items 90–101", topics: ["Newman", "Fischer", "atropisomerism", "chirality"], body: ["The final page-112 source subgroup contains three Newman projections, six Fischer projections, and three sterically hindered biaryls. Each is a separate stereochemical comparison case."], rule: "For a projection keep the stated viewing convention; for a biaryl test both terminal ring paths before calling the rotation axis stereogenic." },
  { number: 42, title: "Atropisomer, ring and constrained-system bank", source: "Optical Isomerism p. 113, items 102–123", topics: ["atropisomerism", "rings", "wedge-dash", "symmetry"], body: ["This source page progresses from crowded aromatic axes to cyclic and fused systems. All 22 numbered structures remain individually visible."], rule: "A solid/hashed bond specifies a ring face; never discard it while testing for a symmetry element." },
  { number: 43, title: "Cyclic, nitrile and aromatic symmetry exercise", source: "Optical Isomerism p. 114, items 124–152", topics: ["rings", "nitriles", "aromatics", "symmetry"], body: ["The source mixes crowded axes, small-ring configurations, halogenated cyclohexanes, nitrile-substituted rings, a cage and aromatic substitution patterns. Every numbered case is separately rendered."], rule: "Symmetry is global: include every substituent, ring path and displayed stereobond." },
  { number: 44, title: "Heteroaryl, rigid-system and ring-face exercise", source: "Optical Isomerism p. 115, items 153–165", topics: ["heteroaromatics", "polycycles", "rings", "chirality"], body: ["The source compares heteroaromatic systems, a fixed polycycle, crowded aromatics, an oligophenyl and five methylcyclopentane face arrangements."], rule: "Wedge/dash marks are structural facts: they cannot be ignored when a ring has multiple substituents." },
  { number: 45, title: "Ring-face and Fischer-projection exercise", source: "Optical Isomerism p. 116, items 166–186", topics: ["rings", "Fischer", "carbohydrates", "symmetry"], body: ["The source combines cyclic face relationships and a ten-member Fischer set. Every individual hydroxyl sequence remains visible."], rule: "In a Fischer projection horizontal bonds are forward and vertical bonds are behind the plane." },
  { number: 46, title: "Fischer, framework and projection exercise", source: "Optical Isomerism p. 117, items 187–203", topics: ["Fischer", "Newman", "frameworks", "carbohydrates"], body: ["The source page spans four Fischer forms, heterocycles, rigid frameworks, three Newman projections, cyclopropyl rings and cyclic carbohydrate structures."], rule: "Use the stated drawing convention and full geometry, rather than a local fragment, in every symmetry test." },
  { number: 47, title: "Sugar, Newman and constrained-ring exercise", source: "Optical Isomerism p. 118, items 204–226", topics: ["carbohydrates", "Newman", "rings", "chirality"], body: ["The source combines six cyclic sugars, seven Newman projections and ten constrained-ring/chain structures as individual cases."], rule: "A projection drawing has a defined viewing convention: preserve it before comparing mirror images or configurations." },
  { number: 48, title: "Final source exercise and answer key", source: "Optical Isomerism p. 119, items 227–255", topics: ["rings", "cages", "aromatics", "answer key"], body: ["The final page supplies items 227–255 and an explicit list of every compound the source classifies as chiral. Each source result is shown with its item."], rule: "Use the printed answer key only after preserving the structure’s full geometry and symmetry information." },
  { number: 49, title: "Double/triple-bond and metamerism examples", source: "Isomerism p. 8", topics: ["functional isomerism", "metamerism", "ethers"], body: ["The page compares unsaturated functional isomers, defines metamerism, lists applicable bivalent/polyvalent groups and gives six explicit ether examples."], rule: "Metamerism requires the same functional group and formula, with a different distribution of carbon-containing groups on either side of a polyvalent centre." },
  { number: 50, title: "Metamerism comparison bank", source: "Isomerism p. 9", topics: ["metamerism", "ethers", "amines", "carbonyls"], body: ["The page classifies source ether comparisons and illustrates metamerism in amines, thioethers, esters, amides, anhydrides, ketones and sulphonates."], rule: "Same formula alone is insufficient: retain the same functional group, then compare alkyl distribution on each side of its polyvalent centre." },
  { number: 51, title: "Metamerism problems and structural-isomer drills", source: "Isomerism p. 10", topics: ["metamerism", "functional isomers", "alkenes", "rings"], body: ["The source presents ether/ester/sulphonate/amine comparison problems and begins structural-isomer enumeration for C₃H₆, C₄H₈ and C₅H₁₀."], rule: "For degree of unsaturation one, enumerate both an alkene and ring branch before deciding that the list is complete." },
  { number: 52, title: "C₅H₁₀ and C₆H₁₂ structural-isomer enumeration", source: "Isomerism p. 11", topics: ["structural isomers", "alkenes", "cycloalkanes", "DU"], body: ["The source completes C₅H₁₀ and displays a broad acyclic/cyclic enumeration for C₆H₁₂ at degree of unsaturation one."], rule: "Avoid duplicate ring structures: a rotation of a ring is not a new constitutional isomer." },
  { number: 53, title: "C₅H₁₂O isomers and pentyl chlorides", source: "Isomerism p. 12", topics: ["alcohols", "ethers", "monohalo derivatives", "symmetry"], body: ["The source enumerates alcohol and ether isomers of C₅H₁₂O and counts monochloro products from the three pentane skeletons."], rule: "For mono-substitution counts, identify symmetry-equivalent hydrogens before replacing any H with Cl." },
  { number: 54, title: "Dichloro-derivative counting", source: "Isomerism p. 13", topics: ["dihalo derivatives", "symmetry", "benzene", "cyclohexane"], body: ["The source counts dichloro products from C₄H₁₀, benzene, cyclohexane and begins the toluene subproblem."], rule: "For positional counting, factor out every symmetry-related placement before treating an arrangement as new." },
  { number: 55, title: "Toluene dichloro derivatives and hydrogenation", source: "Isomerism p. 14", topics: ["toluene", "dihalo derivatives", "alkenes", "hydrogenation"], body: ["The source completes toluene dichloro enumeration and applies a fixed-carbon-skeleton approach to alkene precursors of a branched alkane."], rule: "Hydrogenation preserves connectivity: create a C=C only between adjacent carbons of the given alkane skeleton." },
  { number: 56, title: "Constitutional isomers of alkanes", source: "Isomerism p. 15", topics: ["alkanes", "constitutional isomers", "counting"], body: ["The source tabulates constitutional alkane isomer counts from n = 1 to n = 33, excluding stereoisomers."], rule: "These are structural-isomer counts only; do not add stereoisomers to the tabulated values." },
  { number: 57, title: "Constitutional isomers of alkanes, continued", source: "Isomerism p. 16", topics: ["alkanes", "constitutional isomers", "counting"], body: ["The source continues the exact alkane constitutional-isomer table for n = 34 through n = 67."], rule: "The listed values count non-isomorphic carbon skeletons and still exclude stereoisomers." },
  { number: 58, title: "Constitutional isomers of alkanes, n = 67–100", source: "Isomerism p. 17", topics: ["alkanes", "constitutional isomers", "counting"], body: ["The source concludes the shown high-carbon alkane constitutional-isomer table from n = 67 through n = 100."], rule: "The enormous values remain structural-isomer counts only; stereoisomers are excluded." },
  { number: 59, title: "Tautomerism: definition and defining features", source: "Isomerism p. 18", topics: ["tautomerism", "keto-enol", "equilibrium", "acid-base"], body: ["The source defines tautomerism, shows generic keto–enol interconversion and lists its defining properties."], rule: "Draw tautomers with an equilibrium arrow and include both α-hydrogen migration and π-bond relocation." },
  { number: 60, title: "Further prototropic tautomerism", source: "Isomerism p. 19", topics: ["prototropy", "nitro", "imine", "heterocycles"], body: ["The source gives nitro–aci-nitro, amido–imidol, imine–enamine, nitroso–oximino and azo–hydrazono pairs, then phenol/heterocycle stability cases."], rule: "Aromaticity and solvent can reverse a tautomeric preference; do not assume the carbonyl form always dominates." },
  { number: 61, title: "Pyridine tautomers and ionotropy", source: "Isomerism p. 20", topics: ["pyridones", "solvent", "tautomerism", "ionotropy"], body: ["The source compares 4-pyridone/4-hydroxypyridine in vapour and ethanol, then gives 2-hydroxypyridine/2-pyridone and pyridine-2-thiol/pyridine-2-thione preferences.", "It closes by naming cationotropy and anionotropy as types of tautomerism."], rule: "A solvent can reverse a heterocyclic tautomeric preference; preserve the source’s stated condition." },
  { number: 62, title: "Tautomer stability: source pair bank I", source: "Isomerism p. 54", topics: ["tautomerism", "stability", "carbonyl", "nitrile"], body: ["Five individual source pairs compare the stability of carbonyl-, nitrile-, and vinyl-enol forms."], rule: "A keto form is commonly favoured, but always test whether aromaticity, conjugation or chelation supplies a specific compensating stabilisation." },
  { number: 63, title: "Enol content: source comparison bank II", source: "Isomerism p. 54", topics: ["enol content", "1,3-dicarbonyl", "chelation"], body: ["Four source pairs compare active-methylene compounds, ketones and aryl-substituted diketones."], rule: "Use specific enol stabilisation, not carbonyl count alone, to rank enol content." },
  { number: 64, title: "Enol content: source comparison bank III", source: "Isomerism p. 54", topics: ["enol content", "conjugation", "inductive effect"], body: ["Five source comparisons test cyclic conjugation and α-chloro inductive effects."], rule: "Rank enol content from the stabilisation of the actual enol, not from an isolated functional group." },
  { number: 65, title: "Draw enol forms and assess stability", source: "Isomerism p. 55", topics: ["enolisation", "cyclic carbonyls", "conjugation"], body: ["Source carbonyl structures are converted to their corresponding enols with stability analysis."], rule: "Every enol drawing must preserve the atom skeleton while moving an α-H and the π bond." },
  { number: 66, title: "Why 1,3-dicarbonyl compounds are mostly enolised", source: "Isomerism p. 55", topics: ["1,3-dicarbonyl", "chelation", "conjugation"], body: ["Acetylacetone and a rigid source dicarbonyl illustrate enol stabilisation and structural constraints."], rule: "Two carbonyl groups promote enolisation only when the displayed structure permits the stabilising enol geometry." },
  { number: 67, title: "Ease of enolisation", source: "Isomerism p. 56", topics: ["kinetic isotope effect", "enolate", "1,3-dicarbonyl"], body: ["The source compares acetone, perdeuteroacetone and acetylacetone."], rule: "C-D cleavage is slower than C-H cleavage; distinguish enol equilibrium from rate when the question asks ease." },
  { number: 68, title: "Why the enol can boil lower despite –OH", source: "Isomerism p. 56", topics: ["intramolecular hydrogen bond", "boiling point", "acetylacetone"], body: ["The source contrasts the chelated enol and diketo forms of acetylacetone."], rule: "A visible OH group does not guarantee a higher boiling point: determine whether it is available for intermolecular association." },
  { number: 69, title: "Cyclobutanone and triketocyclobutane enols", source: "Isomerism p. 56", topics: ["enol stability", "conjugation", "cyclic ketones"], body: ["The source compares two strained-ring enol forms."], rule: "Assess the actual enol π system and remaining carbonyl stabilisation." },
  { number: 70, title: "Geometrical-isomer counting: C₂FClBrI", source: "Isomerism p. 60", topics: ["geometrical isomerism", "counting", "alkenes"], body: ["The source counts constitutional distributions and E/Z pairs for a tetrahalogenated ethene."], rule: "First count distinct distributions across C=C, then multiply only by valid independent E/Z alternatives." },
  { number: 71, title: "Which alkenes can show geometrical isomerism?", source: "Isomerism p. 61", topics: ["alkenes", "E/Z eligibility", "rings"], body: ["Source terminal, internal and exocyclic alkene cases are tested individually."], rule: "Each double-bond carbon must have two different substituents." },
  { number: 72, title: "Total acyclic isomers of C₅H₁₀", source: "Isomerism p. 62", topics: ["constitutional isomers", "geometrical isomers", "alkenes"], body: ["The source adds the E/Z pair of pent-2-ene to five acyclic alkene frameworks."], rule: "Count a cis/trans pair twice only when the alkene meets the different-substituent test." },
  { number: 73, title: "Oxime formation and geometrical isomerism", source: "Isomerism p. 63", topics: ["oximes", "syn anti", "C=N"], body: ["The source forms oximes from hydroxylamine and tests aldo-/ketoxime eligibility."], rule: "An oxime needs two different groups at carbon to give geometrical isomerism." },
  { number: 74, title: "Geometrical isomerism around C=N and N=N", source: "Isomerism p. 64", topics: ["imines", "azo compounds", "hyponitrous acid"], body: ["The source extends geometrical-isomer testing beyond C=C."], rule: "At each end of a restricted π system, compare the two substituents." },
  { number: 75, title: "Cis/trans geometrical isomerism in cycloalkanes", source: "Isomerism p. 65", topics: ["cycloalkanes", "cis trans", "ring faces"], body: ["The source uses substituted small rings to show configurationally locked faces."], rule: "Ring-face relationships are configurational, not conformational, differences." },
  { number: 76, title: "Why small cycloalkenes lack trans isomers", source: "Isomerism p. 66", topics: ["cycloalkenes", "ring strain", "cis trans"], body: ["The source excludes small-ring trans cycloalkenes and contrasts cyclooctene."], rule: "Assess ring strain before treating cis/trans alternatives as possible." },
  { number: 77, title: "Cycloalkene cis/trans stability crossover", source: "Isomerism p. 67", topics: ["cycloalkenes", "stability", "conformations"], body: ["The source gives the C8-C11 and C12+ stability crossover."], rule: "Cis/trans stability depends on ring size; do not universalise acyclic-alkene trends." },
  { number: 78, title: "Cumulenes: parity and geometrical isomerism", source: "Isomerism p. 68", topics: ["cumulenes", "allene", "orbital planes"], body: ["The source contrasts even- and odd-double-bond cumulated systems."], rule: "For cumulenes, terminal-plane parity controls geometrical-isomer eligibility." },
];

// Dedicated modules 79–169 are source-page lessons. Keeping this generated
// registration separate avoids recreating their large visual content in this
// selector while making every numeric route visible and statically generated.
const extendedSourceParts: IsomerismPart[] = Array.from({ length: 91 }, (_, index) => {
  const number = index + 79;
  return {
    number,
    title: extendedSourcePartTitles[number],
    source: "Isomerism source",
    topics: ["source lesson", "visual structures"],
    body: ["A dedicated source lesson with rendered structures and worked reasoning."],
  };
});

export const isomerismParts: IsomerismPart[] = [...baseIsomerismParts, ...extendedSourceParts];

function Diagram({ type }: { type: "wedge" | "fischer" | "newman" | "mirror" | "ez" }) {
  if (type === "fischer") return <svg viewBox="0 0 360 220" className="h-auto w-full max-w-md" role="img" aria-label="Fischer projection"><path d="M180 25V195M75 110H285" stroke="currentColor" strokeWidth="5"/><text x="165" y="20">CO₂H</text><text x="170" y="215">CH₃</text><text x="35" y="115">OH</text><text x="292" y="115">H</text><text x="20" y="160" fill="#67e8f9">horizontal: forward</text><text x="20" y="182" fill="#a78bfa">vertical: away</text></svg>;
  if (type === "newman") return <svg viewBox="0 0 300 240" className="h-auto w-full max-w-sm" role="img" aria-label="Newman projection"><circle cx="150" cy="120" r="58" fill="none" stroke="currentColor" strokeWidth="4"/><circle cx="150" cy="120" r="7" fill="currentColor"/><path d="M150 120 80 45M150 120 65 150M150 120 195 205M150 62 150 18M205 150 255 175M95 150 45 180" stroke="currentColor" strokeWidth="4"/><text x="132" y="130">front</text><text x="120" y="110" fill="#67e8f9">rear circle</text></svg>;
  if (type === "mirror") return <svg viewBox="0 0 420 220" className="h-auto w-full max-w-lg" role="img" aria-label="Enantiomer mirror-image comparison"><path d="M210 10V210" stroke="#a78bfa" strokeDasharray="7 7" strokeWidth="3"/><text x="180" y="25" fill="#c4b5fd">mirror</text><path d="M110 112 55 68M110 112 55 162M110 112 160 75M110 112 160 165" stroke="currentColor" strokeWidth="5"/><path d="M310 112 360 68M310 112 360 162M310 112 260 75M310 112 260 165" stroke="currentColor" strokeWidth="5"/><text x="42" y="60">OH</text><text x="42" y="180">H</text><text x="148" y="68">CH₃</text><text x="148" y="185">CO₂H</text><text x="370" y="60">OH</text><text x="370" y="180">H</text><text x="225" y="68">CH₃</text><text x="225" y="185">CO₂H</text></svg>;
  if (type === "ez") return <svg viewBox="0 0 360 200" className="h-auto w-full max-w-md" role="img" aria-label="E Z priority diagram"><path d="M150 100H210" stroke="currentColor" strokeWidth="8"/><path d="M150 92H210" stroke="currentColor" strokeWidth="3"/><path d="M150 108H210" stroke="currentColor" strokeWidth="3"/><path d="M150 100 85 45M150 100 85 160M210 100 275 45M210 100 275 160" stroke="currentColor" strokeWidth="4"/><text x="45" y="45" fill="#67e8f9">1 (high)</text><text x="45" y="178">2</text><text x="270" y="45" fill="#67e8f9">1 (high)</text><text x="280" y="178">2</text><text x="145" y="25" fill="#a78bfa">same side = Z</text></svg>;
  return <svg viewBox="0 0 360 230" className="h-auto w-full max-w-md" role="img" aria-label="Wedge dash stereochemical diagram"><path d="M180 112 95 65M180 112 95 165" stroke="currentColor" strokeWidth="5"/><path d="M180 112 260 65" stroke="currentColor" strokeWidth="11"/><path d="M180 112 260 165" stroke="currentColor" strokeDasharray="4 5" strokeWidth="11"/><text x="45" y="62">OH</text><text x="45" y="180">CH₃</text><text x="268" y="62" fill="#67e8f9">H</text><text x="268" y="180" fill="#a78bfa">CO₂H</text><text x="136" y="108">C*</text><text x="20" y="215" fill="#94a3b8">solid wedge: toward · hashed: away</text></svg>;
}

function PartPage({ part }: { part: IsomerismPart }) {
  const previous = isomerismParts[part.number - 2]; const next = isomerismParts[part.number];
  const diagram = part.number >= 14 ? "wedge" : part.number === 9 ? "newman" : part.number === 7 ? "ez" : part.number === 13 ? "mirror" : part.number === 10 ? "fischer" : "wedge";
  return <main className="min-h-screen bg-[#08111f] px-4 py-8 text-white sm:px-6 sm:py-12"><article className="mx-auto max-w-5xl"><Link href="/learn/isomerism" className="rounded-full border border-cyan-300/30 bg-cyan-300/10 px-4 py-2 text-sm font-bold text-cyan-100">Isomerism</Link><header className="mt-6 rounded-3xl border border-cyan-300/15 bg-[radial-gradient(circle_at_top_right,_rgba(34,211,238,.18),_transparent_35%),linear-gradient(135deg,rgba(34,211,238,.08),rgba(2,6,23,.7),rgba(139,92,246,.1))] p-6 sm:p-9"><p className="text-xs font-black uppercase tracking-[.24em] text-cyan-200">Organic Chemistry · Part {part.number}</p><h1 className="mt-3 text-3xl font-black sm:text-5xl">{part.title}</h1><p className="mt-3 text-sm text-slate-300">Primary source: {part.source}</p><div className="mt-5 h-1.5 rounded-full bg-white/10"><div className="h-full rounded-full bg-gradient-to-r from-cyan-300 to-violet-400" style={{width: `${part.number / isomerismParts.length * 100}%`}} /></div></header><section className="mt-7 grid gap-6 lg:grid-cols-[1fr_.8fr]"><div className="space-y-5"><div className="rounded-2xl border border-white/10 bg-white/[.035] p-5"><h2 className="text-lg font-black text-cyan-200">Core idea</h2>{part.body.map((p) => <p key={p} className="mt-3 text-sm leading-7 text-slate-200 sm:text-base">{p}</p>)}</div>{part.rule && <aside className="rounded-2xl border border-amber-300/25 bg-amber-300/[.07] p-5"><p className="text-xs font-black uppercase tracking-wider text-amber-200">JEE rule / common trap</p><p className="mt-2 text-sm leading-7 text-amber-50">{part.rule}</p></aside>}{part.example && <div className="rounded-2xl border border-violet-300/20 bg-violet-300/[.06] p-5"><p className="text-xs font-black uppercase tracking-wider text-violet-200">Illustration</p><p className="mt-2 text-sm leading-7 text-violet-50">{part.example}</p></div>}</div><figure className="h-fit rounded-2xl border border-cyan-300/20 bg-slate-950/60 p-5 text-slate-100"><Diagram type={diagram as "wedge" | "fischer" | "newman" | "mirror" | "ez"}/><figcaption className="mt-3 border-t border-white/10 pt-3 text-sm text-slate-300">Original responsive stereochemical representation. Use the displayed perspective conventions when assigning configuration.</figcaption></figure></section>{part.number === 11 && <section className="mt-6 rounded-2xl border border-cyan-300/20 bg-cyan-300/[.05] p-5"><h2 className="font-black text-cyan-100">Specific rotation</h2><BlockMath math="[\\alpha]_{\\lambda}^{T}=\\frac{\\alpha_{obs}}{l c}" /><p className="text-sm text-slate-300">Use the specified temperature T and wavelength λ; l is path length (dm) and c is concentration under the stated convention.</p></section>}{part.number === 15 && <section className="mt-6 rounded-2xl border border-cyan-300/20 bg-cyan-300/[.05] p-5"><h2 className="font-black text-cyan-100">Counting checkpoint</h2><BlockMath math="N_{max}=2^n" /><p className="text-sm text-slate-300">This is an upper limit, not an automatic answer. Subtract arrangements made identical by internal symmetry and identify meso cases.</p></section>}<nav className="mt-8 flex justify-between gap-3 border-t border-white/10 pt-6">{previous ? <Link href={`/learn/isomerism/${previous.number}`} className="rounded-xl border border-white/15 px-4 py-3 text-sm font-bold text-slate-200">← {previous.number}</Link> : <span/>}{next ? <Link href={`/learn/isomerism/${next.number}`} className="rounded-xl border border-cyan-300/30 bg-cyan-300/10 px-4 py-3 text-sm font-bold text-cyan-100">{next.number} →</Link> : null}</nav></article></main>;
}

